"""
portal_app/modules/facturacion/facturacion.py
Módulo Beta — Facturación y Cobranza
"""
import streamlit as st
from datetime import date
from modules.facturacion.data_source import get_clientes, get_facturas_cliente

LOGO_B64 = ""

# ─── Perfil de riesgo ─────────────────────────────────────────────────────────
# Devuelve: (etiqueta, color_hex, angulo_aguja)
# Aguja: rotate(-75)=RIESGO(izq), rotate(-25)=VIGILANCIA, rotate(25)=CLIENTE SANO, rotate(75)=EXCELENTE(der)

def _perfil_riesgo(dias_max: int, pct_usado: float):
    if dias_max == 0 and pct_usado < 70:
        return "EXCELENTE",    "#059669",  75   # verde — extremo derecho
    elif dias_max <= 3 and pct_usado < 85:
        return "CLIENTE SANO", "#2E7D32",  25   # verde oscuro — centro-derecha
    elif dias_max <= 10 or pct_usado < 95:
        return "VIGILANCIA",   "#D97706", -25   # naranja — centro-izquierda
    else:
        return "RIESGO",       "#DC2626", -75   # rojo — extremo izquierdo


# ─── Velocímetro ──────────────────────────────────────────────────────────────
def _medidor_riesgo(estado: str, color: str, angulo: int):
    rot = f"rotate({angulo})"
    # Arco: izquierda=RIESGO(rojo), centro=VIGILANCIA(naranja), derecha=EXCELENTE(verde)
    st.markdown(
        '<div style="text-align:center; padding:0.5rem 0;">' +
        '<svg viewBox="0 0 200 130" width="190" style="display:block; margin:auto;">' +
        # Arco rojo (RIESGO) - lado izquierdo
        '<path d="M 25 105 A 80 80 0 0 1 75 30" fill="none" stroke="#DC2626" stroke-width="14" stroke-linecap="round"/>' +
        # Arco naranja (VIGILANCIA) - centro
        '<path d="M 75 30 A 80 80 0 0 1 125 30" fill="none" stroke="#D97706" stroke-width="14" stroke-linecap="round"/>' +
        # Arco verde (EXCELENTE) - lado derecho
        '<path d="M 125 30 A 80 80 0 0 1 175 105" fill="none" stroke="#059669" stroke-width="14" stroke-linecap="round"/>' +
        # Aguja
        f'<g transform="translate(100,105)">' +
        f'<line x1="0" y1="0" x2="0" y2="-60" stroke="#1B2266" stroke-width="3.5" stroke-linecap="round" transform="{rot}"/>' +
        '<circle cx="0" cy="0" r="7" fill="#1B2266"/>' +
        '<circle cx="0" cy="0" r="3.5" fill="white"/>' +
        '</g></svg>' +
        f'<div style="margin-top:-0.3rem;">' +
        f'<span style="background:{color}; color:white; font-size:0.75rem; font-weight:700; ' +
        f'padding:4px 18px; border-radius:20px; text-transform:uppercase; letter-spacing:0.5px;">● {estado}</span>' +
        '</div>' +
        '<div style="display:flex; justify-content:space-between; padding:0 0.5rem; font-size:0.65rem; margin-top:0.5rem;">' +
        '<span style="color:#DC2626; font-weight:600;">Riesgo</span>' +
        '<span style="color:#D97706; font-weight:600;">Vigilancia</span>' +
        '<span style="color:#059669; font-weight:600;">Excelente</span>' +
        '</div></div>',
        unsafe_allow_html=True
    )


# ─── Barra de crédito ─────────────────────────────────────────────────────────
def _barra_credito(usado: float, limite: float, color_perfil: str):
    """Usa el mismo color del perfil de riesgo para consistencia visual."""
    pct = min(usado / limite * 100, 100)
    st.markdown(
        '<div style="padding:0.2rem 0;">' +
        '<div style="display:flex; justify-content:space-between; margin-bottom:0.4rem;">' +
        f'<div><div style="font-size:1.5rem; font-weight:800; color:{color_perfil};">{pct:.0f}%</div>' +
        '<div style="font-size:0.65rem; color:#9CA3AF; text-transform:uppercase;">UTILIZADO</div></div>' +
        f'<div style="text-align:right;"><div style="font-size:1.5rem; font-weight:800; color:#059669;">{100-pct:.0f}%</div>' +
        '<div style="font-size:0.65rem; color:#9CA3AF; text-transform:uppercase;">DISPONIBLE</div></div>' +
        '</div>' +
        '<div style="background:#E5E9F0; border-radius:8px; height:10px; overflow:hidden;">' +
        f'<div style="background:{color_perfil}; width:{pct}%; height:100%; border-radius:8px;"></div></div>' +
        '<div style="display:flex; justify-content:space-between; margin-top:0.4rem; font-size:0.76rem; color:#6B7280;">' +
        f'<span>Usado: <b style="color:{color_perfil};">${usado:,.0f}</b></span>' +
        f'<span>Límite: <b style="color:#1B2266;">${limite:,.0f}</b></span>' +
        '</div></div>',
        unsafe_allow_html=True
    )


# ─── Tabla de facturas ────────────────────────────────────────────────────────
def _tabla_facturas(facturas: list, filtro: str):
    filas = ""
    for f in facturas:
        dias = f["dias_vencido"]
        vencida = dias > 0
        cf = "#DC2626" if vencida else "#1B2266"
        cd = "#DC2626" if vencida else "#059669"
        bd = "#FEE2E2" if vencida else "#D1FAE5"
        ci = "#DC2626" if vencida else "#1B2266"
        if filtro == "Vencidas" and not vencida:
            continue
        if filtro == "Al corriente" and vencida:
            continue
        td = "padding:0.7rem 0.8rem;"
        filas += (
            '<tr style="border-bottom:1px solid #F1F5F9;">' +
            f'<td style="{td} font-weight:700; color:{cf};">{f["folio"]}</td>' +
            f'<td style="{td} color:#6B7280; font-size:0.85rem;">{f["fecha_emision"].strftime("%d %b %Y")}</td>' +
            f'<td style="{td} color:#6B7280; font-size:0.85rem;">{f["fecha_vencimiento"].strftime("%d %b %Y")}</td>' +
            f'<td style="{td}"><span style="background:#EEF0FF; color:#1B2266; font-size:0.78rem; font-weight:600; padding:3px 10px; border-radius:6px; font-family:monospace;">{f["viaje_referencia"]}</span></td>' +
            f'<td style="{td} text-align:center;"><span style="background:{bd}; color:{cd}; font-weight:700; font-size:0.82rem; padding:3px 10px; border-radius:20px; min-width:32px; display:inline-block; text-align:center;">{dias}</span></td>' +
            f'<td style="{td} text-align:right; font-weight:700; font-size:1rem; color:{ci};">${f["importe"]:,.0f}</td>' +
            '</tr>'
        )
    if not filas:
        filas = '<tr><td colspan="6" style="text-align:center; padding:2rem; color:#9CA3AF;">Sin facturas con este filtro</td></tr>'
    th = "padding:0.7rem 0.8rem; font-size:0.72rem; color:#9CA3AF; font-weight:700; text-transform:uppercase; letter-spacing:0.5px;"
    html = (
        '<div style="background:white; border-radius:14px; overflow:hidden; border:1px solid #E5E9F0; box-shadow:0 2px 12px rgba(27,34,102,0.07);">' +
        '<table style="width:100%; border-collapse:collapse;">' +
        '<thead><tr style="background:#F8FAFF; border-bottom:2px solid #E5E9F0;">' +
        f'<th style="{th} text-align:left;">FACTURA</th>' +
        f'<th style="{th} text-align:left;">FECHA</th>' +
        f'<th style="{th} text-align:left;">VENCIMIENTO</th>' +
        f'<th style="{th} text-align:left;">VIAJE</th>' +
        f'<th style="{th} text-align:center;">DÍAS VENCIDO</th>' +
        f'<th style="{th} text-align:right;">IMPORTE USD</th>' +
        '</tr></thead>' +
        f'<tbody>{filas}</tbody>' +
        '</table></div>'
    )
    st.markdown(html, unsafe_allow_html=True)


# ─── Render principal ─────────────────────────────────────────────────────────
def estado_cuenta_page():
    from ui.components import page_banner
    page_banner("💳", "Facturación y Cobranza", "Estado de cuenta por cliente — Beta")

    clientes = get_clientes()
    nombres  = [c["nombre"] for c in clientes]

    # ── Selector estilizado ───────────────────────────────────────────────────
    st.markdown(
        '<div style="font-size:0.70rem; color:#9CA3AF; font-weight:700; ' +
        'text-transform:uppercase; letter-spacing:0.5px; margin-bottom:0.3rem;">🏢 SELECCIONAR CLIENTE</div>',
        unsafe_allow_html=True
    )
    st.markdown("""
    <style>
    div[data-testid="stSelectbox"]:first-of-type > div > div {
        background: white !important;
        border: 2px solid #1B2266 !important;
        border-radius: 10px !important;
        font-weight: 700 !important;
        color: #1B2266 !important;
        box-shadow: 0 2px 8px rgba(27,34,102,0.10) !important;
        font-size: 1rem !important;
    }
    </style>
    """, unsafe_allow_html=True)
    seleccion = st.selectbox("Cliente", nombres, label_visibility="collapsed")

    cliente  = next(c for c in clientes if c["nombre"] == seleccion)
    facturas = get_facturas_cliente(cliente["id"])

    total     = sum(f["importe"] for f in facturas)
    dias_max  = max((f["dias_vencido"] for f in facturas), default=0)
    pct_usado = total / cliente["limite_credito"] * 100
    estado, color_r, angulo = _perfil_riesgo(dias_max, pct_usado)

    # ── Header cliente SIN banner azul ────────────────────────────────────────
    # Logo + nombre en color + datos en gris, sin fondo
    st.markdown(
        '<div style="display:flex; align-items:center; gap:1rem; ' +
        'padding:0.8rem 0.2rem 0.6rem 0.2rem; border-bottom:2px solid #E5E9F0; margin-bottom:1rem;">' +
        f'<img src="data:image/png;base64,{LOGO_B64}" style="height:44px; width:auto; object-fit:contain;">' +
        '<div style="flex:1;">' +
        f'<div style="font-size:1.5rem; font-weight:800; color:#1B2266; line-height:1.1;">{cliente["nombre"]}</div>' +
        f'<div style="font-size:0.8rem; color:#9CA3AF; margin-top:0.1rem;">' +
        f'{cliente["razon_social"]} &nbsp;·&nbsp; ' +
        f'<span style="color:{color_r}; font-weight:700;">{cliente["condiciones_pago"]}</span>' +
        f' &nbsp;·&nbsp; Emitido: {date.today().strftime("%d de %B, %Y")}</div>' +
        '</div>' +
        f'<span style="background:{color_r}22; color:{color_r}; ' +
        f'font-size:0.75rem; font-weight:700; padding:5px 14px; ' +
        f'border-radius:20px; border:1.5px solid {color_r}; text-transform:uppercase; white-space:nowrap;">' +
        f'● {estado}</span>' +
        '</div>',
        unsafe_allow_html=True
    )

    # ── KPIs ──────────────────────────────────────────────────────────────────
    k1, k2, k3, k4 = st.columns(4)
    def kpi(col, label, valor, color="#1B2266"):
        col.markdown(
            f'<div style="background:white; border-radius:10px; padding:0.9rem 1rem; ' +
            f'border:1px solid #E5E9F0; border-top:3px solid {color};">' +
            f'<div style="font-size:0.63rem; color:#9CA3AF; font-weight:700; text-transform:uppercase; letter-spacing:0.5px;">{label}</div>' +
            f'<div style="font-size:1.1rem; font-weight:800; color:{color}; margin-top:0.2rem;">{valor}</div>' +
            '</div>',
            unsafe_allow_html=True
        )
    kpi(k1, "Límite de Crédito", f"${cliente['limite_credito']:,.0f} USD", "#1B2266")
    kpi(k2, "Condiciones",        cliente["condiciones_pago"],               "#6B7280")
    kpi(k3, "Total Balance",      f"${total:,.0f} USD",                      color_r)
    kpi(k4, "Facturas Activas",   f"{len(facturas)} facturas",               "#1B2266")

    st.markdown("<br>", unsafe_allow_html=True)

    # ── Tabla + Panel ─────────────────────────────────────────────────────────
    col_tabla, col_panel = st.columns([6, 3])

    with col_tabla:
        fc1, fc2 = st.columns([3, 1])
        with fc1:
            st.markdown(
                '<div style="font-weight:700; font-size:1rem; color:#1B2266; margin-bottom:0.5rem;">' +
                f'📄 FACTURAS &nbsp;<span style="background:#F1F5F9; color:#9CA3AF; font-size:0.72rem; ' +
                f'padding:3px 10px; border-radius:6px; font-family:monospace; font-weight:400;">' +
                f'As of {date.today().strftime("%d %B %Y")}</span></div>',
                unsafe_allow_html=True
            )
        with fc2:
            filtro = st.selectbox("Filtrar", ["Todas", "Vencidas", "Al corriente"], label_visibility="collapsed")

        _tabla_facturas(facturas, filtro)
        st.markdown(
            '<div style="display:flex; justify-content:flex-end; align-items:center; gap:1rem; ' +
            'padding:0.8rem 1rem; margin-top:0.3rem; background:white; border-radius:10px; border:1px solid #E5E9F0;">' +
            '<span style="font-size:0.85rem; font-weight:600; color:#6B7280;">TOTAL BALANCE</span>' +
            f'<span style="font-size:1.2rem; font-weight:800; color:{color_r};">${total:,.0f} USD</span>' +
            '</div>',
            unsafe_allow_html=True
        )

    with col_panel:
        st.markdown('<div style="font-size:0.65rem; color:#9CA3AF; font-weight:700; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:0.3rem;">PERFIL DE RIESGO</div>', unsafe_allow_html=True)
        with st.container(border=True):
            _medidor_riesgo(estado, color_r, angulo)

        st.markdown("<br>", unsafe_allow_html=True)

        st.markdown('<div style="font-size:0.65rem; color:#9CA3AF; font-weight:700; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:0.3rem;">LÍNEA DE CRÉDITO</div>', unsafe_allow_html=True)
        with st.container(border=True):
            _barra_credito(total, cliente["limite_credito"], color_r)

        st.markdown("<br>", unsafe_allow_html=True)

        st.markdown(
            '<div style="font-size:0.65rem; color:#9CA3AF; font-weight:700; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:0.3rem;">INFORMACIÓN DE PAGO</div>' +
            '<div style="background:white; border-radius:12px; padding:1rem 1.1rem; border:1px solid #E5E9F0;">' +
            f'<div style="font-weight:700; font-size:0.9rem; color:#1B2266; margin-bottom:0.15rem;">{cliente["banco"]}</div>' +
            f'<div style="font-size:0.75rem; color:#9CA3AF; margin-bottom:0.8rem;">{cliente["banco_empresa"]}</div>' +
            '<div style="display:flex; justify-content:space-between; padding:0.4rem 0; border-bottom:1px solid #F1F5F9; font-size:0.8rem;">' +
            f'<span style="color:#9CA3AF;">Cuenta</span><span style="font-weight:700; color:#1B2266; font-family:monospace;">{cliente["cuenta_bancaria"]}</span></div>' +
            '<div style="display:flex; justify-content:space-between; padding:0.4rem 0; border-bottom:1px solid #F1F5F9; font-size:0.8rem;">' +
            f'<span style="color:#9CA3AF;">SWIFT</span><span style="font-weight:700; color:#1B2266; font-family:monospace;">{cliente["swift"]}</span></div>' +
            f'<div style="margin-top:0.8rem; padding:0.5rem 0.8rem; background:#EEF0FF; border-radius:8px; text-align:center;">' +
            f'<span style="color:#CC1E1E; font-weight:700; font-size:0.83rem;">📞 {cliente["telefono"]}</span></div>' +
            f'<div style="font-size:0.70rem; color:#9CA3AF; margin-top:0.7rem; line-height:1.4; text-align:center;">{cliente["notas_pago"]}</div>' +
            '</div>',
            unsafe_allow_html=True
        )
